# tests/architecture/cost/test_max_tokens_required.py
import ast, pathlib, pytest

SOURCE_ROOT = pathlib.Path("src/")

class MaxTokensChecker(ast.NodeVisitor):
    def __init__(self, filename):
        self.filename    = filename
        self.violations  = []

    def visit_Call(self, node):
        # Detect calls matching: <anything>.messages.create(...)
        if (isinstance(node.func, ast.Attribute)
                and node.func.attr == "create"
                and isinstance(node.func.value, ast.Attribute)
                and node.func.value.attr == "messages"):
            kwargs = {kw.arg for kw in node.keywords}
            if "max_tokens" not in kwargs:
                self.violations.append(
                    f"  {self.filename}:{node.lineno} — messages.create() missing max_tokens"
                )
        self.generic_visit(node)

violations = []
for path in SOURCE_ROOT.rglob("*.py"):
    try:
        tree = ast.parse(path.read_text())
    except SyntaxError:
        continue
    checker = MaxTokensChecker(str(path))
    checker.visit(tree)
    violations.extend(checker.violations)

@pytest.mark.parametrize("violation", violations if violations else [None])
def test_max_tokens_set(violation):
    if violation is None:
        return  # no violations found — pass
    pytest.fail(
        f"FF-COST-01 FAILED: LLM call without max_tokens:\n{violation}\n"
        "Set max_tokens to the task-appropriate ceiling:\n"
        "  Summarisation: ≤512   Chat: ≤2048   Generation: ≤4096"
    )

# tests/architecture/cost/test_no_unbounded_batch.py
# Detects async for loops or list comprehensions that call the LLM
# without an enclosing Semaphore or ThreadPoolExecutor.
import ast, pathlib, pytest

SOURCE_ROOT = pathlib.Path("src/")
LLM_CALL_MARKERS = {"messages.create", "complete", "call_llm", "llm_call"}

class BatchLoopChecker(ast.NodeVisitor):
    def __init__(self):
        self.violations = []
        self._in_semaphore = False

    def visit_AsyncWith(self, node):
        # Check if context manager is a Semaphore (async with sem:)
        for item in node.items:
            if isinstance(item.context_expr, ast.Name):
                if "sem" in item.context_expr.id.lower() or "semaphore" in item.context_expr.id.lower():
                    old = self._in_semaphore
                    self._in_semaphore = True
                    self.generic_visit(node)
                    self._in_semaphore = old
                    return
        self.generic_visit(node)

    def visit_AsyncFor(self, node):
        # An async for loop that contains an LLM call without a semaphore is risky
        if not self._in_semaphore:
            for child in ast.walk(node):
                if isinstance(child, ast.Call):
                    call_str = ast.unparse(child)
                    if any(m in call_str for m in LLM_CALL_MARKERS):
                        self.violations.append(
                            f"Line {node.lineno}: async for loop with LLM call "
                            f"but no enclosing Semaphore detected"
                        )
                        break
        self.generic_visit(node)

@pytest.mark.parametrize("source_file", list(SOURCE_ROOT.rglob("*.py")))
def test_no_unbounded_batch_llm_loop(source_file):
    try:
        tree = ast.parse(source_file.read_text())
    except SyntaxError:
        return
    checker = BatchLoopChecker()
    checker.visit(tree)
    assert not checker.violations, (
        f"FF-COST-02 FAILED in {source_file}:\n"
        + "\n".join(checker.violations) + "\n"
        "Wrap batch LLM loops in an asyncio.Semaphore:\n"
        "  sem = asyncio.Semaphore(20)\n"
        "  async with sem:\n"
        "      result = await call_llm(...)"
    )

# tests/architecture/cost/test_model_upgrade_budget_review.py
import subprocess, yaml, pathlib, sys, pytest

# Anthropic model pricing tiers (relative cost, not exact pricing)
# Higher tier = more expensive
MODEL_TIERS = {
    "claude-haiku-4-5-20251001":  1,
    "claude-sonnet-4-6":          5,
    "claude-opus-4-8":            15,
}

def get_base_yaml(path: str) -> dict | None:
    result = subprocess.run(
        ["git", "show", f"origin/main:{path}"],
        capture_output=True, text=True
    )
    if result.returncode != 0:
        return None
    return yaml.safe_load(result.stdout)

changed_files = subprocess.check_output(
    ["git", "diff", "--name-only", "origin/main...HEAD", "--", "prompts/"]
).decode().splitlines()

violations = []
for rel_path in changed_files:
    path = pathlib.Path(rel_path)
    if not path.exists():
        continue
    current = yaml.safe_load(path.read_text())
    base    = get_base_yaml(rel_path)
    if base is None:
        continue

    current_model = current.get("model", "")
    base_model    = base.get("model", "")
    current_tier  = MODEL_TIERS.get(current_model, 0)
    base_tier     = MODEL_TIERS.get(base_model, 0)

    if current_tier > base_tier:
        # Model was upgraded — check if p95_cost_usd was also updated
        current_cost = current.get("token_budget", {}).get("p95_cost_usd")
        base_cost    = base.get("token_budget", {}).get("p95_cost_usd")
        if current_cost == base_cost:
            violations.append(
                f"{rel_path}: model upgraded {base_model} → {current_model} "
                f"but token_budget.p95_cost_usd was not updated ({base_cost}). "
                "Update the cost estimate to reflect the new model's pricing."
            )

@pytest.mark.parametrize("violation", violations if violations else [None])
def test_model_upgrade_has_budget_review(violation):
    if violation is None:
        return
    pytest.fail(f"FF-COST-04 FAILED:\n{violation}")

# src/adapters/llm_adapter.py (relevant section)
import tiktoken  # pip install tiktoken (works for approximate token counting)

class LLMAdapter:
    def __init__(self, model: str, max_tokens: int, max_input_tokens: int = 4096):
        self.model           = model
        self.max_tokens      = max_tokens
        self.max_input_tokens = max_input_tokens
        # tiktoken cl100k_base is a reasonable approximation for Claude token counts
        self._encoder = tiktoken.get_encoding("cl100k_base")

    def _count_tokens(self, text: str) -> int:
        return len(self._encoder.encode(text))

    def _truncate_to_budget(self, system: str, user_message: str) -> str:
        system_tokens  = self._count_tokens(system)
        budget_for_user = self.max_input_tokens - system_tokens - 20  # 20-token safety margin

        if budget_for_user <= 0:
            raise ValueError(
                f"System prompt alone ({system_tokens} tokens) exceeds "
                f"max_input_tokens ({self.max_input_tokens}). "
                "Reduce system prompt length."
            )

        user_tokens = self._count_tokens(user_message)
        if user_tokens <= budget_for_user:
            return user_message  # fits — no truncation needed

        # Truncate: encode → slice → decode
        encoded  = self._encoder.encode(user_message)
        truncated = self._encoder.decode(encoded[:budget_for_user])
        return truncated + "\n[Input truncated to fit token budget]"

    def complete(self, system: str, user_message: str) -> str:
        safe_message = self._truncate_to_budget(system, user_message)
        response = self._client.messages.create(
            model=self.model,
            max_tokens=self.max_tokens,
            system=system,
            messages=[{"role": "user", "content": safe_message}],
        )
        if response.stop_reason == "max_tokens":
            # Log and surface truncation — do not silently return incomplete output
            self._emit_truncation_metric()
        return response.content[0].text

# scripts/check_cost_anomalies.py
# Run hourly from CI or a scheduled job.
# Compares current-hour cost per feature against 7-day baseline.
import os, requests, json

DD_API  = "https://api.datadoghq.com/api/v1/query"
HEADERS = {
    "DD-API-KEY":         os.environ["DD_API_KEY"],
    "DD-APPLICATION-KEY": os.environ["DD_APP_KEY"],
}

def query_metric(q: str, hours: int = 1) -> float:
    import time
    now  = int(time.time())
    resp = requests.get(DD_API, headers=HEADERS, params={
        "from": now - hours * 3600, "to": now, "query": q
    })
    series = resp.json().get("series", [])
    if not series:
        return 0.0
    points = [p[1] for p in series[0]["pointlist"] if p[1] is not None]
    return sum(points) / len(points) if points else 0.0

def check_cost_spike(feature: str) -> dict | None:
    current_hour  = query_metric(f"avg:llm.cost_usd{{llm.feature:{feature}}}.as_rate()")
    baseline      = query_metric(f"avg:llm.cost_usd{{llm.feature:{feature}}}.as_rate()", hours=7*24)

    if baseline == 0:
        return None  # no baseline yet — skip

    ratio = current_hour / baseline
    if ratio > 2.0:
        return {
            "feature":      feature,
            "current_usd_h": current_hour,
            "baseline_usd_h": baseline,
            "ratio":        ratio,
            "severity":     "P1" if ratio > 5.0 else "P2",
        }
    return None

FEATURES = ["document_summariser", "chat_assistant", "code_reviewer"]
anomalies = [a for f in FEATURES if (a := check_cost_spike(f))]

if anomalies:
    print(json.dumps({"anomalies": anomalies}, indent=2))
    for a in anomalies:
        print(f"[{a['severity']}] {a['feature']}: cost {a['ratio']:.1f}× baseline")
    raise SystemExit(1)
else:
    print("No cost anomalies detected")

# scripts/audit_prompt_size.py
import subprocess, yaml, pathlib

BLOAT_THRESHOLD = 1.20   # 20% growth over 4 weeks triggers a warning
FOUR_WEEKS_AGO  = subprocess.check_output(
    ["git", "rev-list", "--before=4.weeks.ago", "-1", "main"]
).decode().strip()

def get_system_token_count(content: str) -> int:
    # Approximate: split on whitespace, multiply by 1.3 (rough word-to-token ratio)
    return int(len(content.split()) * 1.3)

bloat_warnings = []
for path in pathlib.Path("prompts/").glob("**/*.yaml"):
    # Get current system prompt token count
    current_data   = yaml.safe_load(path.read_text())
    current_tokens = get_system_token_count(current_data.get("system", ""))

    # Get 4-weeks-ago system prompt token count
    result = subprocess.run(
        ["git", "show", f"{FOUR_WEEKS_AGO}:{path}"],
        capture_output=True, text=True
    )
    if result.returncode != 0:
        continue   # new file — skip
    old_data   = yaml.safe_load(result.stdout)
    old_tokens = get_system_token_count(old_data.get("system", ""))

    if old_tokens == 0:
        continue
    growth = current_tokens / old_tokens
    if growth > BLOAT_THRESHOLD:
        bloat_warnings.append({
            "prompt":         str(path),
            "old_tokens":     old_tokens,
            "current_tokens": current_tokens,
            "growth_pct":     round((growth - 1) * 100, 1),
        })

if bloat_warnings:
    print("PROMPT BLOAT DETECTED:")
    for w in bloat_warnings:
        print(f"  {w['prompt']}: {w['old_tokens']} → {w['current_tokens']} tokens "
              f"(+{w['growth_pct']}% in 4 weeks)")
    print("Review each prompt and remove instructions that are no longer needed.")
else:
    print("No prompt bloat detected")

# scripts/audit_cost_vs_budget.py
# Compare actual monthly cost per feature against the budget declared
# in token_budget.monthly_budget_usd in each prompt YAML.
import os, yaml, pathlib, requests

DD_API  = "https://api.datadoghq.com/api/v1/query"
HEADERS = {"DD-API-KEY": os.environ["DD_API_KEY"], "DD-APPLICATION-KEY": os.environ["DD_APP_KEY"]}

def get_monthly_actual_cost(feature: str) -> float:
    import time
    now = int(time.time())
    resp = requests.get(DD_API, headers=HEADERS, params={
        "from": now - 30 * 24 * 3600, "to": now,
        "query": f"sum:llm.cost_usd{{llm.feature:{feature}}}"
    })
    series = resp.json().get("series", [])
    if not series:
        return 0.0
    return sum(p[1] for p in series[0]["pointlist"] if p[1])

budget_violations = []
for path in pathlib.Path("prompts/").glob("**/*.yaml"):
    data   = yaml.safe_load(path.read_text())
    budget = data.get("token_budget", {}).get("monthly_budget_usd")
    if budget is None:
        continue

    feature = data.get("id", path.stem)
    actual  = get_monthly_actual_cost(feature)

    if actual > budget * 0.8:   # warn at 80% of budget
        budget_violations.append({
            "prompt":    str(path),
            "feature":   feature,
            "budget":    budget,
            "actual":    round(actual, 2),
            "pct_used":  round(actual / budget * 100, 1),
            "over_budget": actual > budget,
        })

if budget_violations:
    print("COST BUDGET WARNINGS:")
    for v in budget_violations:
        status = "OVER BUDGET" if v["over_budget"] else f"{v['pct_used']}% of budget"
        print(f"  {v['feature']}: ${v['actual']:.2f} actual vs ${v['budget']:.2f} budget ({status})")
    print("Raise budgets if traffic grew, or optimise if costs exceeded expectations.")
